SET client_encoding TO 'UTF8';

SET check_function_bodies = false;

CREATE OR REPLACE VIEW view_sctransdep (data_code, bank_code, trandate, seq_tran, seq_no, membership_no, cmember_name, amount, acc_no, member_group_no, c_reference, eng_name, item_type, branch_bank_code, fee_amount, begining_of_contract, branch_id, loan_type, trans_bank_status, item_seq_no) AS SELECT
        ' ' as data_code,  
        sc_dep_t_deposit_slip_item.bank_code  as bank_code , 
        ' ' as trandate,  
        ' ' as seq_tran,  
        row_number() OVER () as seq_no,
        sc_dep_m_creditor.membership_no as membership_no ,
        sc_mem_m_ucf_prename.prename || '' ||
        sc_mem_m_membership_registered.member_name || ' ' ||
        sc_mem_m_membership_registered.member_surname as cmember_name ,
        sc_dep_t_deposit_slip_item.item_amount  as  amount ,
        trim(both sc_dep_t_deposit_slip_item.bank_acc_no)  as  acc_no,
        sc_mem_m_membership_registered.member_group_no as member_group_no,
        sc_dep_m_creditor.deposit_account_no as c_reference ,
        sc_mem_m_membership_registered.eng_name as eng_name ,
        sc_dep_t_deposit_slip_item.deposit_slip_no as item_type ,
        left((trim(both sc_dep_t_deposit_slip_item.bank_acc_no)),3) as branch_bank_code,
        0 as fee_amount,
        sc_dep_t_deposit_slip.working_day  as begining_of_contract
,sc_dep_t_deposit_slip.branch_id as branch_id
,sc_dep_m_creditor.deposit_type_code as loan_type 
,sc_dep_t_deposit_slip_item.trans_bank_status as trans_bank_status
,sc_dep_t_deposit_slip_item.seq_no as item_seq_no
FROM sc_mem_m_membership_registered ,
  sc_mem_m_ucf_prename ,
  sc_dep_m_creditor ,
  sc_dep_t_deposit_slip_item   ,
  sc_dep_t_deposit_slip
where ( sc_mem_m_membership_registered.prename_code = sc_mem_m_ucf_prename.prename_code ) 
  and ( sc_mem_m_membership_registered.membership_no = sc_dep_m_creditor.membership_no ) 
  and ( sc_dep_m_creditor.deposit_account_no = sc_dep_t_deposit_slip.account_no )   
  and ( sc_dep_t_deposit_slip.deposit_slip_no = sc_dep_t_deposit_slip_item.deposit_slip_no )
  and sc_dep_t_deposit_slip.cancel_status = '0'
  and sc_dep_t_deposit_slip.deposit_slip_type in ( 'WDR','CCA' )
    /*WHERE*/

--and sc_dep_t_deposit_slip.working_day between adtm_bdate and adtm_edate
--and sc_dep_t_deposit_slip.branch_id = as_branch_id
 

order by sc_dep_m_creditor.deposit_account_no asc;

